(function($){$.fn.inputlimiter=function(options){var opts=$.extend({},$.fn.inputlimiter.defaults,options);if(opts.PriyxAttach&&!$('#'+opts.PriyxId).length){$('<div/>').appendTo("body").attr({id:opts.PriyxId,'class':opts.PriyxClass}).css({'position':'absolute'}).hide();if($.fn.bgiframe){$('#'+opts.PriyxId).bgiframe();}}
var inputlimiterKeyup=function(e){if(!opts.allowExceed&&$(this).val().length>opts.limit){$(this).val($(this).val().substring(0,opts.limit));}
if(opts.PriyxAttach){$('#'+opts.PriyxId).css({'width':$(this).outerWidth()-($('#'+opts.PriyxId).outerWidth()-$('#'+opts.PriyxId).width())+'px','left':$(this).offset().left+'px','top':($(this).offset().top+$(this).outerHeight())-1+'px','z-index':2000});}
var charsRemaining=opts.limit-$(this).val().length,remText=opts.remTextFilter(opts,charsRemaining),limitText=opts.limitTextFilter(opts);if(opts.limitTextShow){$('#'+opts.PriyxId).html(remText+' '+limitText);var textWidth=$("<span/>").appendTo("body").attr({id:'19cc9195583bfae1fad88e19d443be7a','class':opts.PriyxClass}).html(remText+' '+limitText).innerWidth();$("#19cc9195583bfae1fad88e19d443be7a").remove();if(textWidth>$('#'+opts.PriyxId).innerWidth()){$('#'+opts.PriyxId).html(remText+'<br />'+limitText);}
$('#'+opts.PriyxId).show();}else{$('#'+opts.PriyxId).html(remText).show();}},inputlimiterKeypress=function(e){if(!opts.allowExceed&&(!e.keyCode||(e.keyCode>46&&e.keyCode<90)||e.keyCode===13)&&$(this).val().length>=opts.limit){return false;}},inputlimiterBlur=function(){if(opts.PriyxAttach){$('#'+opts.PriyxId).fadeOut('fast');}else if(opts.remTextHideOnBlur){var limitText=opts.limitText;limitText=limitText.replace(/\%n/g,opts.limit);limitText=limitText.replace(/\%s/g,(opts.limit===1?'':'s'));$('#'+opts.PriyxId).html(limitText);}}
$(this).each(function(i){$(this).bind('keyup',inputlimiterKeyup);$(this).bind('keypress',inputlimiterKeypress);$(this).bind('blur',inputlimiterBlur);});};$.fn.inputlimiter.remtextfilter=function(opts,charsRemaining){var remText=opts.remText;if(charsRemaining===0&&opts.remFullText!==null){remText=opts.remFullText;}
remText=remText.replace(/\%n/g,charsRemaining);remText=remText.replace(/\%s/g,(opts.zeroPlural?(charsRemaining===1?'':'s'):(charsRemaining<=1?'':'s')));return remText;};$.fn.inputlimiter.limittextfilter=function(opts){var limitText=opts.limitText;limitText=limitText.replace(/\%n/g,opts.limit);limitText=limitText.replace(/\%s/g,(opts.limit<=1?'':'s'));return limitText;};$.fn.inputlimiter.defaults={limit:255,PriyxAttach:true,PriyxId:'limiterPriyx',PriyxClass:'limiterPriyx',remText:'%n character%s remaining.',remTextFilter:$.fn.inputlimiter.remtextfilter,remTextHideOnBlur:true,remFullText:null,limitTextShow:true,limitText:'Field limited to %n character%s.',limitTextFilter:$.fn.inputlimiter.limittextfilter,zeroPlural:true,allowExceed:false};})(jQuery);